import React, { useEffect, useState } from 'react';
import { AsyncStorage, Button, View } from 'react-native';
import { authorize, refresh, AuthConfiguration } from 'react-native-app-auth';

const config: AuthConfiguration = {
  clientId: 'YOUR_CLIENT_ID',
  clientSecret: 'YOUR_CLIENT_SECRET',
  redirectUrl: 'YOUR_APP_REDIRECT_URL',
  serviceConfiguration: {
    authorizationEndpoint: 'YOUR_AUTHORIZATION_ENDPOINT',
    tokenEndpoint: 'YOUR_TOKEN_ENDPOINT',
  },
  scopes: ['YOUR_REQUIRED_SCOPES'],
};

export default function App() {
  const [accessToken, setAccessToken] = useState(null);

  useEffect(() => {
    (async () => {
      const storedRefreshToken = await AsyncStorage.getItem('refreshToken');
      if (!storedRefreshToken) {
        return;
      }
      const { accessToken: newToken } = await refresh(config, {
        refreshToken: storedRefreshToken,
      });
      setAccessToken(newToken);
    })();
  }, []);

  const handleLogin = async () => {
    const result = await authorize(config);
    await AsyncStorage.setItem('refreshToken', result.refreshToken);
    setAccessToken(result.accessToken);
  };

  return (
    <View>
      {!accessToken ? (
        <Button title="Login" onPress={handleLogin} />
      ) : (
        <Text>Logged in with access token: {accessToken}</Text>
      )}
    </View>
  );
}